pub type DepositRedeemer {
  input_a: Int,
  input_b: Int,
  reserve_a: Int,
  reserve_b: Int,
  total_lp: Int,
  min_deposit: Int,
}

// ── Validator ─────────────────────────────────────────────────────────────────

validator lp_min_deposit(policy_id: PolicyId) {
  mint(redeemer: DepositRedeemer, _policy: PolicyId, self: Transaction) {
    let DepositRedeemer {
      input_a,
      input_b,
      reserve_a,
      reserve_b,
      total_lp,
      min_deposit,
    } = redeemer

    when
      safe_lp_for_deposit(
        input_a,
        input_b,
        reserve_a,
        reserve_b,
        total_lp,
        min_deposit,
      )
    is {
      None -> False
      Some(expected_lp) -> {
        let minted_tokens = tokens(self.mint, policy_id)
        mint_amount_valid(minted_tokens, expected_lp)
      }
    }
  }

  else(_) {
    fail
  }
}

