fn can_settle(
  validity_range: interval.Interval,
  end_time:       Int,
  winning_bid:    Int,
  reserve_price:  Int,
) -> Bool {
  interval.is_entirely_after(validity_range, end_time) && meets_reserve(winning_bid, reserve_price)
}

/// Auction can be cancelled (no sale) if bid never met reserve
fn can_cancel(
  validity_range: interval.Interval,
  end_time:       Int,
  winning_bid:    Int,
  reserve_price:  Int,
) -> Bool {
  interval.is_entirely_after(validity_range, end_time) && !meets_reserve(winning_bid, reserve_price)
}

