validator auction_extension(_policy_id: PolicyId) {
  spend(
    datum: Option<AuctionDatum>,
    redeemer: BidRedeemer,
    _output_ref,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let BidRedeemer { bid_slot, bid_amount } = redeemer
    let new_end = extended_deadline(bid_slot, d.current_end, d.extension, d.snipe_window)
    let deadline_ok = extension_non_decreasing(bid_slot, d.current_end, d.extension, d.snipe_window)
    let no_early_sneak = !early_bid_no_extension(bid_slot, d.current_end, d.extension, d.snipe_window) || new_end == d.current_end
    let bid_sufficient = bid_amount >= d.prev_bid + d.min_increment
    let _ = self.inputs
    deadline_ok && no_early_sneak && bid_sufficient
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_snipe_extends_deadline(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(1, 50)),
) {
  let (end, ext) = vals
  // bid at exact end triggers extension
  extended_deadline(end, end, ext, 0) == end + ext
}

test prop_early_bid_unchanged(
  vals via fuzz.both(fuzz.int_between(200, 500), fuzz.int_between(1, 50)),
) {
  let (end, ext) = vals
  early_bid_no_extension(0, end, ext, 10)
}

test prop_deadline_never_decreases(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 100)),
) {
  let (bid_slot, end) = vals
  extension_non_decreasing(bid_slot, end, 50, 10)
}

test prop_no_extension_when_window_zero(
  bid_slot via fuzz.int_between(0, 1000),
) {
  // snipe_window == 0 means any bid at or after end triggers extension
  let end = 500
  when bid_slot >= end is {
    True -> extended_deadline(bid_slot, end, 10, 0) == end + 10
    False -> extended_deadline(bid_slot, end, 10, 0) == end
  }
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// early_bid_no_extension returns False when bid_slot + win >= end,
// because the condition bid_slot + win < end is not satisfied.
// Here bid_slot >= end and win >= 0 guarantees bid_slot + win >= end.
test prop_late_bid_fails_early_bid_check(
  vals via fuzz.both(fuzz.int_between(500, 1000), fuzz.int_between(0, 50)),
) fail {
  let (bid_slot, win) = vals
  // end = 499, so bid_slot >= 500 > 499, meaning bid_slot + win >= end always
  expect early_bid_no_extension(bid_slot, 499, 10, win)
}

// early_bid_no_extension returns False when ext > 0 and the bid is
// within the snipe window, because extended_deadline != end.
// bid_slot=490, end=500, win=20: 490+20=510 >= 500 so it extends → result != end
test prop_snipe_bid_fails_early_bid_check() fail {
  // bid_slot + win = 490 + 20 = 510 >= 500, so early_bid_no_extension is False
  expect early_bid_no_extension(490, 500, 10, 20)
}

// extension_non_decreasing returns False only if extended_deadline < end,
// which cannot happen by construction — so we target early_bid_no_extension
// with a bid exactly at the boundary where extension fires but ext is negative.
// With a negative extension the new_end < end, making extension_non_decreasing False.
test prop_negative_extension_violates_non_decreasing(
  ext via fuzz.int_between(-500, -1),
) fail {
  // bid at end with negative extension: extended_deadline = end + ext < end
  expect extension_non_decreasing(100, 100, ext, 0)
}

// early_bid_no_extension is False when bid_slot + win >= end regardless of ext,
// because the first conjunct (bid_slot + win < end) fails.
// Use bid_slot = end to guarantee bid_slot + win >= end for any win >= 0.
test prop_bid_at_end_fails_early_bid_check(
  vals via fuzz.both(fuzz.int_between(1, 500), fuzz.int_between(0, 100)),
) fail {
  let (end, win) = vals
  // bid_slot == end, so bid_slot + win = end + win >= end — first conjunct False
  expect early_bid_no_extension(end, end, 1, win)
}

/// Dutch auction: price decreases linearly from start_price to floor_price
/// over the interval [start_slot, end_slot]
use aiken/fuzz
use cardano/transaction.{Transaction, InlineDatum, Output}
use aiken/collection/list
fn dutch_price(
  start_price: Int,
  floor_price: Int,
  start_slot:  Int,
  end_slot:    Int,
  current_slot: Int,
) -> Int {
  if current_slot <= start_slot {
    start_price
  } else if current_slot >= end_slot {
    floor_price
  } else {
    let elapsed  = current_slot - start_slot
    let duration = end_slot - start_slot
    let drop     = (start_price - floor_price) * elapsed / duration
    start_price - drop
  }
}

/// Price is always between floor and start
fn price_in_bounds(
  start_price: Int,
  floor_price: Int,
  start_slot:  Int,
  end_slot:    Int,
  current_slot: Int,
) -> Bool {
  let p = dutch_price(start_price, floor_price, start_slot, end_slot, current_slot)
  p >= floor_price && p <= start_price
}

// ── Datum / Redeemer types ───────────────────────────────────────────────────

pub type AuctionDatum {
  start_price: Int,
  floor_price: Int,
  start_slot: Int,
  end_slot: Int,
  seller_pkh: ByteArray,
}

pub type AuctionRedeemer {
  Buy { current_slot: Int, paid_amount: Int }
  Cancel
}

// ── Validator ────────────────────────────────────────────────────────────────

validator dutch_auction {
  spend(
    datum: Option<AuctionDatum>,
    redeemer: AuctionRedeemer,
    _own_ref: Data,
    self: Transaction,
  ) {
    when (datum, redeemer) is {
      (Some(d), Buy { current_slot, paid_amount }) -> {
        let required_price =
          dutch_price(d.start_price, d.floor_price, d.start_slot, d.end_slot, current_slot)
        let valid_price = price_in_bounds(d.start_price, d.floor_price, d.start_slot, d.end_slot, current_slot)
        let buyer_pays_enough = paid_amount >= required_price
        let seller_receives =
          list.any(
            self.outputs,
            fn(o: Output) { o.value |> fn(v) { True } },
          )
        valid_price && buyer_pays_enough && seller_receives
      }
      (Some(d), Cancel) ->
        list.any(
          self.extra_signatories,
          fn(signer) { signer == d.seller_pkh },
        )
      _ -> False
    }
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_price_at_start_is_max(
  vals via fuzz.both(fuzz.int_between(100, 1000), fuzz.int_between(1, 99)),
) {
  let (start, floor) = vals
  dutch_price(start, floor, 0, 100, 0) == start
}

test prop_price_at_end_is_floor(
  vals via fuzz.both(fuzz.int_between(100, 1000), fuzz.int_between(1, 99)),
) {
  let (start, floor) = vals
  dutch_price(start, floor, 0, 100, 100) == floor
}

test prop_price_always_in_bounds(
  vals via fuzz.both(fuzz.int_between(0, 200), fuzz.int_between(1, 99)),
) {
  let (current_slot, floor) = vals
  price_in_bounds(100, floor, 0, 200, current_slot)
}

test prop_price_non_increasing_over_time(
  vals via fuzz.both(fuzz.int_between(0, 99), fuzz.int_between(1, 99)),
) {
  let (t1, floor) = vals
  let t2 = t1 + 1
  dutch_price(100, floor, 0, 100, t1) >= dutch_price(100, floor, 0, 100, t2)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

/// price_in_bounds must return False when start_price < floor_price
/// because dutch_price returns start_price which is below floor_price.
test prop_inverted_prices_out_of_bounds(
  vals via fuzz.both(fuzz.int_between(1, 50), fuzz.int_between(51, 200)),
) fail {
  let (start_price, floor_price) = vals
  // start_price < floor_price: at slot 0 the price equals start_price,
  // which is strictly less than floor_price, so p >= floor_price is False.
  expect price_in_bounds(start_price, floor_price, 0, 100, 0)
}

/// price_in_bounds must return False when paid_amount is below the floor price
/// and we treat floor as the lower bound — here we verify the bound check itself:
/// start_price == floor_price - 1 makes the price sit below floor every time.
test prop_price_below_floor_rejected(
  floor via fuzz.int_between(2, 1000),
) fail {
  let start_price = floor - 1
  // start_price < floor_price, so at any slot the computed price (start_price)
  // fails the p >= floor_price check.
  expect price_in_bounds(start_price, floor, 0, 100, 0)
}

/// price_in_bounds must return False when the price exceeds start_price.
/// We achieve this by passing a negative floor_price so that dutch_price
/// can return start_price, but we set start_price negative and floor_price
/// as a larger (less-negative) number, making start < floor again.
test prop_negative_start_below_floor_rejected(
  vals via fuzz.both(fuzz.int_between(1, 500), fuzz.int_between(1, 500)),
) fail {
  let (a, b) = vals
  // floor_price = a+b+1 > start_price = a, so price (= start_price = a) < floor
  expect price_in_bounds(a, a + b + 1, 0, 100, 0)
}

/// dutch_price at a mid-slot must never equal the floor when
/// start_price is strictly greater and we have not reached end_slot.
/// We use price_in_bounds with start_price == floor_price - 1 to always fail.
test prop_zero_start_price_below_positive_floor_rejected() fail {
  // start_price=0, floor_price=1: price=0 < floor=1 → False
  expect price_in_bounds(0, 1, 0, 100, 50)
}

