  name via cfuzz.asset_name(),
) fail {
  expect allowlisted_mint(dict.empty, [name])
}

/// allowlisted_mint returns False when qty is zero (not > 0)
test prop_zero_qty_mint_rejected(
  name via cfuzz.asset_name(),
) fail {
