  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.policy_id()),
) {
  let (owner, policy) = vals
  let nonce = #"cafebabe"
  let expected = param_hash3(owner, policy, nonce)
  !params_match3(#"deadbeef", policy, nonce, expected)
}

test prop_wrong_policy_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.policy_id()),
) {
  let (owner, policy) = vals
