) {
  let (bid_qty, ask_qty) = vals
  let filled = fill_amount(bid_qty, ask_qty)
  filled <= bid_qty && filled <= ask_qty
}

test prop_remaining_after_full_fill(qty via fuzz.int_at_least(1)) {
  remaining_after_fill(qty, qty) == 0
