      reference_script: None,
    }
  let new_out =
    Output {
      address: address.from_verification_key(#"aabb"),
      value: assets.from_lovelace(1),
      datum: InlineDatum(n + jump),
      reference_script: None,
    }
  expect counter_incremented(old_out, new_out)
}

